/**
 * @summary Export search results as JSON
 */
export const getExportResultsUrl = (
  searchId: number,
  params?: ExportResultsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/export/${searchId}?${stringifiedParams}`
    : `/api/export/${searchId}`;
};

export const exportResults = async (
  searchId: number,
  params?: ExportResultsParams,
  options?: RequestInit,
): Promise<ExportData> => {
  return customFetch<ExportData>(getExportResultsUrl(searchId, params), {
    ...options,
    method: "GET",
  });
};

export const getExportResultsQueryKey = (
  searchId: number,
  params?: ExportResultsParams,
) => {
  return [`/api/export/${searchId}`, ...(params ? [params] : [])] as const;
};

export const getExportResultsQueryOptions = <
  TData = Awaited<ReturnType<typeof exportResults>>,
  TError = ErrorType<unknown>,
>(
  searchId: number,
  params?: ExportResultsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof exportResults>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getExportResultsQueryKey(searchId, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof exportResults>>> = ({
    signal,
  }) => exportResults(searchId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!searchId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof exportResults>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

